#meals-stat-card {
  background-color: #ffffff;
  border: 1px solid #cccccc;
  border-radius: 8px;
  padding: 16px;
  display: flex;
  align-items: center;
  gap: 16px;
  width: 100%;
  max-width:400px;
}

#meals-stat-icon {
  font-size: 32px;
}

#meals-stat-number {
  font-size: 28px;
  font-weight: bold;
  color: #111111;
}

#meals-stat-label {
  font-size: 13px;
  color: #666666;
  margin-top: 4px;
